import { Routes } from '@angular/router';
import { authGuard } from './core/guards/auth.guard';
import { adminGuard } from './core/guards/admin.guard';
import { FlowRoute } from './flow-meta';

// `data.flow` is the single source of truth for the user-flow graph AND the runtime navbar.
// The colossus flow-graph extractor projects it directly (zero heuristics). Authoring rules
// + lint: docs/flow-graph-convention.md + platform/flowgraph-static/verify/flow-lint.mjs.
//
// DEEP-LINKABLE STATE — every navigable UI state a user could leave feedback on must be
// reachable by URL. Filters/modals here are bound to query params (?q, ?status, ?modal, ?edit)
// so the component restores them from the URL.
export const routes: Routes = ([
  {
    path: 'login',
    loadComponent: () => import('./features/login/login.component').then((m) => m.LoginComponent),
    data: { flow: { flowId: 'login', node: 'login', entry: true, edgesTo: ['catalog', 'signup'], label: 'Login' } },
  },
  {
    path: 'signup',
    loadComponent: () => import('./features/signup/signup.component').then((m) => m.SignupComponent),
    data: { flow: { flowId: 'signup', node: 'signup', edgesTo: ['login', 'catalog'], label: 'Sign up' } },
  },
  {
    path: '',
    loadComponent: () =>
      import('./shared/storefront-layout.component').then((m) => m.StorefrontLayoutComponent),
    children: [
      {
        path: '',
        loadComponent: () => import('./features/catalog/catalog.component').then((m) => m.CatalogComponent),
        data: { flow: { flowId: 'catalog', node: 'catalog', showInNavbar: true, label: 'Catalog', scope: 'all', edgesTo: ['product-detail', 'cart'] } },
      },
      {
        path: 'products/:id',
        loadComponent: () => import('./features/product-detail/product-detail.component').then((m) => m.ProductDetailComponent),
        data: { flow: { flowId: 'product-detail', node: 'product-detail', label: 'Product', edgesTo: ['cart', 'catalog'] } },
      },
      {
        path: 'cart',
        loadComponent: () => import('./features/cart/cart.component').then((m) => m.CartComponent),
        canActivate: [authGuard],
        data: { flow: { flowId: 'cart', node: 'cart', showInNavbar: true, label: 'Cart', scope: 'shopper', edgesTo: ['checkout', 'catalog'] } },
      },
      {
        path: 'checkout',
        loadComponent: () => import('./features/checkout/checkout.component').then((m) => m.CheckoutComponent),
        canActivate: [authGuard],
        data: { flow: { flowId: 'checkout', node: 'checkout', label: 'Checkout', edgesTo: ['order-detail', 'cart'] } },
      },
      {
        path: 'orders',
        loadComponent: () => import('./features/orders/order-history.component').then((m) => m.OrderHistoryComponent),
        canActivate: [authGuard],
        data: { flow: { flowId: 'orders', node: 'orders', showInNavbar: true, label: 'Orders', scope: 'shopper', edgesTo: ['order-detail'] } },
      },
      {
        path: 'orders/:id',
        loadComponent: () => import('./features/orders/order-detail.component').then((m) => m.OrderDetailComponent),
        canActivate: [authGuard],
        data: { flow: { flowId: 'order-detail', node: 'order-detail', label: 'Order detail', edgesTo: ['orders'] } },
      },
      {
        path: 'admin/products',
        loadComponent: () => import('./features/admin/admin-products.component').then((m) => m.AdminProductsComponent),
        canActivate: [adminGuard],
        data: { flow: { flowId: 'admin-products', node: 'admin-products', showInNavbar: true, label: 'Manage products', scope: 'admin', edgesTo: ['admin-orders', 'catalog'] } },
      },
      {
        path: 'admin/orders',
        loadComponent: () => import('./features/admin/admin-orders.component').then((m) => m.AdminOrdersComponent),
        canActivate: [adminGuard],
        data: { flow: { flowId: 'admin-orders', node: 'admin-orders', showInNavbar: true, label: 'Manage orders', scope: 'admin', edgesTo: ['order-detail'] } },
      },
    ],
  },
  { path: '**', redirectTo: '' },
] satisfies FlowRoute[]) as Routes;
